{% load static %}
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>RescueNet - Incident Management</title>
    <link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />
    <script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>
    <meta name="referrer" content="no-referrer-when-downgrade">
    <link rel="stylesheet" href="{% static 'management/css/common_badges.css' %}">

    <style>
        body, html { margin: 0; padding: 0; font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; background: #f4f7f6; height: 100%; }

        /* GŁÓWNY UKŁAD */
        .app-container { display: flex; min-height: 100vh; width: 100%; }

        /* PASEK BOCZNY */
        .sidebar { 
            width: 260px; background: #000; color: white; display: flex; flex-direction: column; 
            position: fixed; height: 100vh; transition: 0.3s;
        }
        .logo { padding: 30px 20px; font-size: 24px; font-weight: bold; color: #d32f2f; text-align: center; }
        .nav-item { 
            padding: 15px 25px; text-decoration: none; color: #bbb; display: block; 
            transition: 0.3s; font-size: 14px;
        }
        .nav-item:hover { color: #fff; background: #1a1a1a; }
        .nav-item.active { background: #fff; color: #000; font-weight: bold; border-radius: 10px 0 0 10px; margin-left: 10px; }

        /* TREŚĆ GŁÓWNA */
        .main-content { 
            flex: 1; 
            padding: 40px; 
            background: #f4f7f6; 
            /* Jeśli sidebar istnieje, przesuń treść w prawo */
            margin-left: 260px; 
        }

        /* Jeśli użytkownik NIE jest zalogowany (strona logowania), usuwamy margines */
        .no-sidebar .main-content { margin-left: 0; display: flex; align-items: center; justify-content: center; }

        /* shared status/priority badges live in management/css/common_badges.css */
    </style>
</head>
<body class="{% if not user.is_authenticated %}no-sidebar{% endif %}">

    <div class="app-container">
        {% if user.is_authenticated %}
        <div class="sidebar">
    <div class="logo">Rescue Net</div>

    <a href="{% url 'dashboard' %}" class="nav-item {% if request.resolver_match.url_name == 'dashboard' %}active{% endif %}">
        Dashboard
    </a>

    {% if user.rola == 'dyspozytor' or user.is_superuser %}
    <a href="{% url 'nowy_incydent' %}" class="nav-item {% if request.resolver_match.url_name == 'nowy_incydent' %}active{% endif %}" style="color: #ff5252; font-weight: bold;">
        + New Incident
    </a>
    {% endif %}

    <a href="{% url 'lista_incydentow' %}" class="nav-item {% if request.resolver_match.url_name == 'lista_incydentow' %}active{% endif %}">
        Incidents
    </a>
    <a href="{% url 'lista_zasobow' %}" class="nav-item {% if request.resolver_match.url_name == 'lista_zasobow' %}active{% endif %}">
        Resources
    </a>
    <a href="{% url 'archiwum' %}" class="nav-item {% if request.resolver_match.url_name == 'archiwum' %}active{% endif %}">
        Reports & Archive
    </a>
            <div style="margin-top: auto; padding: 30px 20px; border-top: 1px solid #333;">
                <p style="font-size: 12px; color: #666; margin-bottom: 10px;">Logged in as: <br><strong>{{ user.username }}</strong></p>
                <form action="{% url 'logout' %}" method="post">
                    {% csrf_token %}
                    <button type="submit" style="background: none; border: none; color: #d32f2f; cursor: pointer; padding: 0; font-weight: bold;">Logout →</button>
                </form>
            </div>
        </div>
        {% endif %}

        <main class="main-content">
            {% block content %}
            {% endblock %}
        </main>
    </div>

</body>
</html>

