{% extends 'management/base.html' %}

{% block content %}
<link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />
<script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>

<h2>Report New Incident</h2>
<p>Fill in the details to dispatch rescue units. <strong>Click on the map to set the exact location.</strong></p>

<div style="background: #fff; padding: 30px; border-radius: 12px; max-width: 600px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);">
    <form method="POST">
        {% csrf_token %}

        {% for field in form %}
            <div style="margin-bottom: 15px;">
                <label style="display: block; margin-bottom: 5px; font-weight: bold;">{{ field.label }}</label>
                {{ field }}
            </div>
        {% endfor %}

        <div style="margin-bottom: 20px; margin-top: 10px;">
            <label style="display: block; margin-bottom: 5px; font-weight: bold;">Incident Location (Interactive Map)</label>
            <div id="map" style="height: 300px; width: 100%; border-radius: 8px; border: 1px solid #ddd; z-index: 1;"></div>
            <small style="color: #888;">Drag the pin or click anywhere on the map to update the coordinates automatically.</small>
        </div>

        <button type="submit" style="background: #d32f2f; color: white; border: none; padding: 12px 25px; border-radius: 8px; cursor: pointer; font-weight: bold;">
            Confirm and Report
        </button>
        <a href="{% url 'lista_incydentow' %}" style="margin-left: 15px; color: #666; text-decoration: none;">Cancel</a>
    </form>
</div>

<style>
    .form-control { width: 100%; padding: 10px; border: 1px solid #ddd; border-radius: 6px; box-sizing: border-box; }
</style>

<script>
    document.addEventListener("DOMContentLoaded", function() {

        var map = L.map('map').setView([51.1079, 17.0385], 12);

        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
            maxZoom: 19,
            attribution: '© OpenStreetMap'
        }).addTo(map);


        var marker = L.marker([51.1079, 17.0385], {draggable: true}).addTo(map);


        function wpiszWspolrzedne(lat, lng) {

            var latInput = document.getElementById('id_lat');
            var lngInput = document.getElementById('id_lng');

            if (latInput && lngInput) {
                latInput.value = lat.toFixed(6);
                lngInput.value = lng.toFixed(6);
            }
        }


        marker.on('dragend', function(e) {
            var pozycja = marker.getLatLng();
            wpiszWspolrzedne(pozycja.lat, pozycja.lng);
        });


        map.on('click', function(e) {
            marker.setLatLng(e.latlng);
            wpiszWspolrzedne(e.latlng.lat, e.latlng.lng);
        });


        wpiszWspolrzedne(51.1079, 17.0385);
    });
</script>
{% endblock %}

{% extends 'management/base.html' %}

{% block content %}
<h2>Report New Incident</h2>
<p>Fill in the details to dispatch rescue units. <strong>Click on the map to set the exact location.</strong></p>

<div style="background: #fff; padding: 30px; border-radius: 12px; width: 100%; box-sizing: border-box; box-shadow: 0 4px 6px rgba(0,0,0,0.1);">
    <form method="POST">
        {% csrf_token %}

        {% for field in form %}
        <div style="margin-bottom: 15px;">
            <label style="display: block; margin-bottom: 5px; font-weight: bold;">{{ field.label }}</label>
            {{ field }}
            {% if field.errors %}
            <p style="color: #d32f2f; font-size: 13px; margin: 5px 0 0 0;">{{ field.errors|join:", " }}</p>
            {% endif %}
        </div>
        {% endfor %}

        <div style="margin-top: 20px; margin-bottom: 15px;">
            <label style="display: block; margin-bottom: 8px; font-weight: bold;">Incident Location (Interactive Map)</label>
            <p style="margin: 0 0 10px 0; font-size: 13px; color: #666;">Click the map to place a marker, then drag it if needed. Latitude/Longitude fields above update automatically.</p>
            <div id="map" style="height: 320px; border: 1px solid #ddd; border-radius: 8px;"></div>
        </div>

        <div style="margin-top: 25px; display: flex; align-items: center; gap: 15px;">
            <button type="submit" style="background: #000; color: #fff; border: none; padding: 12px 25px; border-radius: 8px; cursor: pointer; font-weight: bold;">
                Confirm and Report
            </button>
            <a href="{% url 'lista_incydentow' %}" style="color: #666; text-decoration: none;">Cancel</a>
        </div>
    </form>
</div>

<style>
    .form-control { width: 100%; padding: 10px; border: 1px solid #ddd; border-radius: 6px; box-sizing: border-box; }
    .form-control:focus { outline: none; border-color: #000; }
</style>

<script>
    document.addEventListener('DOMContentLoaded', function() {
        const latInput = document.getElementById('id_lat');
        const lngInput = document.getElementById('id_lng');

        if (!latInput || !lngInput) {
            return;
        }

        latInput.readOnly = true;
        lngInput.readOnly = true;
        latInput.style.background = '#f9f9f9';
        lngInput.style.background = '#f9f9f9';

        const fallbackLat = 51.1079;
        const fallbackLng = 17.0385;

        const parseCoordinate = (value) => {
            if (!value) return NaN;
            return parseFloat(String(value).replace(',', '.'));
        };

        const setCoords = (lat, lng) => {
            latInput.value = lat.toFixed(6);
            lngInput.value = lng.toFixed(6);
        };

        const initialLat = parseCoordinate(latInput.value);
        const initialLng = parseCoordinate(lngInput.value);
        const hasInitialCoords = !isNaN(initialLat) && !isNaN(initialLng) && initialLat !== 0 && initialLng !== 0;

        const startLat = hasInitialCoords ? initialLat : fallbackLat;
        const startLng = hasInitialCoords ? initialLng : fallbackLng;

        const map = L.map('map').setView([startLat, startLng], 13);

        L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
            attribution: '© CARTO'
        }).addTo(map);

        const marker = L.marker([startLat, startLng], { draggable: true }).addTo(map);

        marker.on('dragend', function() {
            const pos = marker.getLatLng();
            setCoords(pos.lat, pos.lng);
        });

        map.on('click', function(e) {
            marker.setLatLng(e.latlng);
            setCoords(e.latlng.lat, e.latlng.lng);
        });

        if (!hasInitialCoords) {
            setCoords(startLat, startLng);
        }

        setTimeout(function() { map.invalidateSize(); }, 150);
    });
</script>
{% endblock %}
